void Next_Combination()

/*Generate the next subset in dictionary order of the subset (a_1, a_2,...., a_m) ≠ (n-m+1,...,n)*

{
    i = m

    while (a[i] == n-m+i):
        i = i-1

    a[i] = a[i] + 1

    for j in range (i+1, m+1):
        a[j] = a[i] + j - i
}
